queries.sparql:
PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?transactiontype ?date WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasTransactions ?child ; p:hasBank_Statements ?parent . } GROUP BY ?child }
  ?child p:TransactionType ?transactiontype .
  ?child p:Date ?date .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Bank_Statements } }
  FILTER(?nf = ?total)
}

